import{Q as s}from"./QSeparator.f2c6b98d.js";import{Q as r,a as c,b as n,c as d}from"./QPage.7e76761f.js";import{P as h}from"./PersonalPageLinks.01d288ae.js";import{E as u}from"./EssentialLink.ec06d8e0.js";import{_ as p,I as m,J as _,K as i,L as a,V as e,M as o}from"./index.84a54032.js";import"./QList.95e0c606.js";import"./QResizeObserver.ca2c1478.js";const g={name:"PersonalTools",components:{PersonalPageLinks:h,EssentialLink:u}},y={class:"row"},f={class:"col-4"},k={class:"col-6"},w=e("h5",null," Obsidian ",-1),v=e("p",null," Obsidian is a smart Markdown editor that allows you to use internal note links. ",-1),b=e("p",null,` Marketed as a "second brain" or knowledge base, it's not unlike other software like Notion. `,-1),T=e("p",null," What I really enjoy about Obsidian, though, is its customisability and flexibility through community plugins. ",-1),I=e("p",null," You can add plugins for just about anything, from custom templating, calendars, code syntax highlighting and Git integration. ",-1),L=e("p",null," Additionally, the files are saved and organised as plain Markdown files inside plain folders, meaning you can open/edit them with other software, and keep all your files even in the case of Obsidian deprecation. I.e., it's future proof! ",-1),x=e("p",{class:"extra-space"},null,-1),P=e("h5",null," VS Code ",-1),C=e("p",null," VS Code is my editor of choice. ",-1),S=e("p",null," Again, extensibility, customisation and an active community are important factors. ",-1),X=e("p",null," To me, the internal links and note-taking relevant plugins in Obsidian, mentioned above, make it worthwile to have Obsidian in addition to another text editor, but in general I like to have everything in one place. As far as text editors go, VS Code is that to me. ",-1),O=e("p",null," I've been curious about learning Emacs, but as I have integrated separate desktop applications for other purposes into my workflow and I am comfortable navigating my OS's desktop environment, I have yet to look into it properly. ",-1),W=e("p",null," To my understanding, Emacs is meant to be the center-piece of your system. Therefore, I have opted to learn Vim keybindings in baby steps, with a Vim emulator in VS Code. ",-1),V=e("p",{class:"extra-space"},null,-1),E=e("h5",null," TeX Live & LaTeX Workshop ",-1),M=e("p",null," LaTeX is a clever document format that allows you to insert special symbols, format your text, and add citations and references easily. It's kind of like a programming language, but the output is a text document. ",-1),G=e("p",null," To edit LaTeX files, I prefer to work with desktop environment and local files over online editors like Overleaf. ",-1),Q=e("p",null," Therefore, I use TeX Live with the LaTeX Workshop extension in VS Code to edit my LaTeX files. ",-1),B=e("p",null," This is also handy because I can set up Overleaf integration using GitHub if I'm collaborating or want to share my files. ",-1),j=e("p",null," TeX Live is a full TeX system containing the major programs, packages, etc. that you need to work with TeX files locally on your computer. It's open-source, regularly maintained, and available on Windows, macOS and most Linux distros. ",-1),A=e("p",null," LaTeX Workshop lets you build your LaTeX files and preview them live inside VS Code. I usually use the PDF preview side-by-side with my source code while writing. ",-1),N=e("p",{class:"extra-space"},null,-1),$=e("h5",null," Google Calendar & Morgen ",-1),F=e("p",null," I use Google Calendar as the central hub for all my other calendar applications. Whether it's my phone, my Windows computer, or my Ubuntu computer, I have all their respective apps synchronise via Google Calendar. ",-1),H=e("p",null," It's not optimal to grant Google access to even more of my information, but at least I never miss a meeting. ",-1),J=e("p",null," Additionally, I'm currently using the Morgen app. I like the aesthetic choices the team has made, its light customisability, and that it has a global hotkey (alt+C) to show/hide the app. It's available on Windows, macOS and all major Linux distros. ",-1),Y=e("p",{class:"extra-space"},null,-1),D=e("h5",null," PowerToys & Everything ",-1),K=e("p",null," This last one is for those of us running Windows on our computer, and wishing it was as easy as using Linux. ",-1),R=e("p",null," The most noticable difference in my workflow was in launching programs and searching for files on Windows. If you've used Linux, you know the Windows start menu just doesn't cut it. ",-1),U=e("p",null," PowerToys is a utility bundle from Microsoft themselves and contains many functions you may not use. However, its file launching feature, PowerToys Run, is worth checking out. It's like launching using the Super key, or using the macOS Spotlight. I also like the Color Picker utility. ",-1),q=e("p",null," I also prefer it over alternative tools like FlowLauncher (non-optimal search results) and ueli (moves around when custom scaling is enabled). ",-1),z=e("p",null," When it comes to searching, though, you may need something even more thorough. That's where voidtools' Everything comes in. Like its name implies, it allows you to search for everything on your machine. And it's fast! ",-1),Z=e("p",{class:"extra-space"},null,-1);function ee(oe,te,se,ne,ie,ae){const l=a("PersonalPageLinks"),t=a("EssentialLink");return m(),_(r,{padding:""},{default:i(()=>[e("div",y,[e("div",f,[o(l)]),e("div",k,[w,v,b,T,I,L,o(t,{class:"link",title:"Obsidian",link:"https://obsidian.md/"}),x,o(s,{class:"separator"}),P,C,S,X,O,W,o(t,{class:"link",title:"VS Code",link:"https://code.visualstudio.com/"}),V,o(s,{class:"separator"}),E,M,G,Q,B,j,A,o(t,{class:"link",title:"TeX Live",link:"https://www.tug.org/texlive/"}),o(t,{class:"link",title:"LaTeX Workshop",link:"https://marketplace.visualstudio.com/items?itemName=James-Yu.latex-workshop"}),N,o(s,{class:"separator"}),$,F,H,J,o(t,{class:"link",title:"Google Calendar",link:"https://calendar.google.com/"}),o(t,{class:"link",title:"Morgen",link:"https://www.morgen.so/"}),Y,o(s,{class:"separator"}),D,K,R,U,q,z,o(t,{class:"link",title:"PowerToys",link:"https://learn.microsoft.com/en-us/windows/powertoys/"}),o(t,{class:"link",title:"Everything",link:"https://www.voidtools.com/"}),Z])]),o(d,{class:"row footer"},{default:i(()=>[o(c,null,{default:i(()=>[o(n,{class:"inactive-label",label:"~"}),o(n,{class:"inactive-label",label:"Sophie Bosio",to:"/"}),o(n,{class:"inactive-label",label:"personal",to:"/personal"}),o(n,{label:"tools",to:"/personal/tools"})]),_:1})]),_:1})]),_:1})}var me=p(g,[["render",ee]]);export{me as default};
